var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"좋아. 코스튬 재료도 잔뜩 모았고. 청소도 대충 이쯤이면 되겠지.","JPN":"よし。コスチュームの材料もたくさん集めたし。掃除もこのくらいでいいよね。","ENG":"Okay. We got all the materials for the costumes, and it looks pretty clean here now.","TWN":"好，服裝材料也收集了很多，打掃到這程度應該就可以了吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"실전은 오랜만이네요. 갑자기 이런 복장으로 싸우게 될 줄은 몰랐지만.","JPN":"実戦は久しぶりですね。いきなりこんな服装で戦うことになるとは思っていませんでしたけど。","ENG":"It's been a long time since I've fought. I didn't know it would be so difficult to fight in an outfit like this, however.","TWN":"好久沒有實戰了，沒想到會突然穿著這種服裝戰鬥。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"심의회라고 했나? 수녀님도 꽤 제법이네.","JPN":"審議会だっけ？　シスターもなかなかやるね。","ENG":"Did you say you were from the Investigation Council? You fight pretty good for a Sister.","TWN":"議會是吧？修女也挺厲害的嘛。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그보다 신기하네요. 카페의 지하실이 이면세계와 연결되어 있다니.","JPN":"それより不思議ですね。カフェの地下室が裏世界と繋がっているなんて。","ENG":"It's interesting to see the basement of a cafe be connected to the Counterside.","TWN":"比這個更神奇的是，咖啡廳的地下室竟然與異界相連。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"특정한 좌표의 이면세계를 어딘가에 연결하는 기술이 있다는 건 처음 알았네요.","JPN":"特定座標の裏世界をどこかに繋げる技術があるということを初めて知りました。","ENG":"I didn't know until now that there is a technology that certain coordinates are connected to somewhere in the Counterside.","TWN":"原來還有特定座標可以連接異界某處的技術啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"여기 오는 사람들은 다 그 소리 하더라?","JPN":"ここに来る人はみんなそう言うんだよね。","ENG":"Everyone who comes here seems to say that.","TWN":"來這裡的人都這麼說。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"원리 같은 건 잘 모르는데, 마법으로 좌표를 고정해 둔 거래.","JPN":"原理はよくわかんないけど、魔法で座標を固定したんだって。","ENG":"We don't know how it works, but we're told magic was used to fix the coordinates.","TWN":"原理什麼的我不太清楚，不過好像是用魔法固定了座標。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"카페 주변에서 침식 현상이 발생하지 않는 것도 주기적으로 여길 청소해서 그런 거고.","JPN":"カフェの周りで侵食現象が発生しないのも、定期的にここを掃除するからだし。","ENG":"And the reason why there are no Counterside Effects around the cafe is because we regularly sweep the basement.","TWN":"咖啡廳周圍沒有發生侵蝕現象，也是因為定期在這裡打掃的緣故。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇군요. 그래서 청소라고…….","JPN":"そうなのですか。だから、掃除って……","ENG":"I see. So that's what \\"cleaning\\" meant...","TWN":"這樣啊，所以是特別的打掃……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"아, 맞다. 이 지하실에 관한 건 비밀이다?","JPN":"あっ、そうだ。この地下室のことは内緒ね。","ENG":"Oh, right. The thing about the basement is a secret, okay?","TWN":"啊，對了，關於這個地下室的事情是秘密喔？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"외부인을 끌어들였다는 걸 라우라가 알면, 귀찮아지거든.","JPN":"部外者を巻き込んだことをラウラが知ると、面倒くさくなるから。","ENG":"If Laura finds out that we brought an outsider down there, things will become troublesome.","TWN":"如果蘿拉知道我們帶外人來，會很麻煩的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후후, 걱정 마세요. 주님을 따르는 이들은 침묵을 미덕으로 여긴답니다.","JPN":"ふふ、心配しないでください。神に従う者たちは沈黙こそ美徳であると思っていますよ。","ENG":"Haha, don't worry. Those who follow the Lord consider silence a virtue.","TWN":"呵呵，不用擔心。追隨主的人們視沉默為美德。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"그런가…? 그 전기톱 꼬맹이는 꽤 요란스러웠던 것 같은데…….","JPN":"そうかな……？　あのチェーンソーのチビちゃんは結構騒がしかったような……","ENG":"Do they...? That chainsaw kid was pretty talkative, if you catch my drift...","TWN":"是嗎…？那個拿電鋸的小鬼好像挺吵的……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"앗, 폐점 시간에 딱 맞춰서 돌아왔네.","JPN":"あっ、閉店時間ぴったりに戻ってきたね。","ENG":"Oh, look. You're back just in time for closing.","TWN":"啊，剛好趕在關門時間回來了。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"고생했어, 잉그리드. 수녀님도 진짜 고생 많으셨어요.","JPN":"お疲れ様、イングリッド。シスターも本当にお疲れ様でした。","ENG":"You did good, Ingrid. And thank you for helping, Sister.","TWN":"辛苦了，英格麗。修女你也真的辛苦了。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"천만에요, 유나 씨. 신세는 저희 자매님이 먼저 지신 걸요.","JPN":"とんでもないです、ユナさん。そもそもシスター・シンディがお世話になってますから。","ENG":"You're welcome, Yuna. But I am just returning the favor.","TWN":"哪裡的話，尤娜。是我們姊妹先領受了你的恩惠。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그보다 옷을 만든다고 하지 않았나요? 이런 재료들로 정말 옷을 만들 수 있는 건가요?","JPN":"それより、服を作ると言っていませんでしたか？　本当にこんな材料で服を作れるのですか？","ENG":"By the way, didn't you say you were making clothes? Can you really make clothes with these materials?","TWN":"比起這個，你不是說要做衣服嗎？用這些材料真的能做出衣服嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"아하하… 재료가 조금 괴팍해 보이긴 하죠.","JPN":"あはは……材料がちょっと変わってますよね。","ENG":"Ah hah hah... I know the materials look a bit odd.","TWN":"啊哈哈……材料看起來有點奇怪吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"이대로 바로 쓰는 건 아니고, 몇 번 가공을 거치면 의상 재료로 사용할 수 있더라고요.","JPN":"このまま使うわけじゃなくて、何回か加工すると衣装の材料として使えるらしいんです。","ENG":"We can't use them like this, and they will only be used as garments after going through a few processes.","TWN":"不能直接使用，需要經過幾次加工後才能作為服裝材料使用。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇군요. 스트레가 분들은 참 신기한 기술을 많이 알고 계시네요.","JPN":"そうなんですか。ストレガのみなさんは本当に不思議な技術をたくさん知っていますね。","ENG":"I see. Strega seems to know about a lot of amazing skills.","TWN":"原來如此，史特雷加的人真是懂得很多神奇的技術呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저… 그래서 말인데…….","JPN":"あの……それでなんですけど……","ENG":"Um... By the way...","TWN":"我……那個……"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"혹시 두 분께 실례가 안 된다면, 한 가지 부탁드리고 싶은 게 있는데요.","JPN":"もしお二人に失礼でなければ、1つお願いしたいことがあるのです。","ENG":"There is a favor I would like to ask if you two don't mind.","TWN":"如果不介意的話，我有個請求想拜託兩位。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"네? 부탁이요?","JPN":"え？　お願いですか？","ENG":"Huh? A favor?","TWN":"啊？請求嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"……특별한 디저트에 쓸 재료를 찾고 계신다고요?","JPN":"……特別なデザートに使う材料を探してるんですか？","ENG":"...You're looking for ingredients to be used for a special dessert?","TWN":"……你在尋找製作特別甜點的材料嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"네. 스트레가는 특별한 디저트로 유명한 카페라고 들었거든요.","JPN":"はい。ストレガは特別なデザートで有名なカフェだと聞きました。","ENG":"Yes. And I heard that Cafe Strega is famous for special desserts.","TWN":"是的，我聽說史特雷加是一家以特別甜點聞名的咖啡廳。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"특별한 디저트를 만드는 가게라면, 그 재료도 특별한 걸 쓰지 않겠어요?","JPN":"特別なデザートを作るお店なら、その材料も特別ではないですか？","ENG":"I thought that a cafe that makes special desserts would use special ingredients as well.","TWN":"如果是製作特別甜點的店，使用的材料也應該是特別的吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"하핫, 우리 디저트가 조금 특별하긴 하지!","JPN":"ははっ、私たちのデザートはちょっと特別だよね！","ENG":"Haha! You're right about our dessert being special!","TWN":"哈哈，我們的甜點確實有點特別！"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"그렇지만 그런 재료들은 에블린 언니한테 물어봐야 할 것 같은데…….","JPN":"でも、その材料はエヴリン姉さんに聞いてみないと……","ENG":"But you'll need to ask Evelyn for ingredients...","TWN":"不過這些材料好像得問問伊芙琳姐姐……"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"부탁드릴게요. 소중한 분들을 위해, 특별한 성탄제를 준비하고 있거든요.","JPN":"お願いします。大切な方々のために、特別な聖誕祭を準備しているのです。","ENG":"Is there any way you could help? I'm trying to make the Christmas party really special for some people I care about.","TWN":"拜託了，我正在為重要的人準備特別的聖誕節。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"비용이라면 얼마든지 지불하겠습니다.","JPN":"お金ならいくらでも払いますから。","ENG":"I'll pay whatever it costs.","TWN":"如果是費用的話，多少都無所謂。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"아, 아니에요!","JPN":"あ、いいえ！","ENG":"N-no need to do that!","TWN":"啊，不是的！"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"수녀님이야말로 저희를 도와주셨잖아요. 그러니까 저희도 도와드려야죠.","JPN":"シスターこそ私たちを助けてくれたじゃないですか。だから、私たちも手伝うべきだと思います。","ENG":"You helped us, so we should also help you.","TWN":"修女你才是幫助了我們啊，所以我們也要幫你才對。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"역시 친절하시네요. 이 또한 자비로운 주님이 베푸신 은총이겠죠.","JPN":"やはりお優しいですね。これもまた慈しみ深い神からの恵なのでしょう。","ENG":"You're all so kind. Perhaps this, too, is a blessing from the merciful Lord.","TWN":"果然很親切呢，這也是仁慈的主賜予的恩典吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"어이, 수녀님. 착각하면 곤란하다구?","JPN":"おい、シスター。勘違いは困るよ。","ENG":"Hey, Sister. Let's get one thing straight.","TWN":"喂，修女，不要誤會了喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"이건 주님이 베푸는 게 아니라, 마녀가 베푸는 호의니까.","JPN":"これは神様からじゃなくて、魔女からの厚意なんだから。","ENG":"This isn't the Lord's blessing. It's a witch's kindness.","TWN":"這不是主的恩典，而是魔女的恩惠。"},"stage":{"bg":"CAFE_STREGA","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"어디보자… 젤라틴이라면 그 젤리 만들 때 쓰는 그거 맞죠?","JPN":"どれどれ……ゼラチンなら、ゼリーを作る時に使うあれですよね？","ENG":"Let’s see here... Gelatin is what's used to make jelly, right?","TWN":"讓我看看……如果是吉利丁的話，就是做果凍時用的那個，對吧？"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"에블린 언니가 유령 마시멜로 만들고 남았던 게 여기 어디 있었던 것 같은데……?","JPN":"エヴリン姉さんが幽霊マシュマロを作って残ったものがここら辺にあったような……？","ENG":"I'm sure Evelyn had some leftovers after making those Ghost Marshmallows...","TWN":"伊芙琳姐姐做幽靈棉花糖剩下的好像就在這裡……？"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"엇! 찾았다! 젤라틴 파우더!","JPN":"あっ！　あった！　ゼラチンパウダー！","ENG":"Oh! Gelatin powder! I found it!","TWN":"啊！找到了！吉利丁粉！"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"잠깐, 글자가 번져서 잘 안 보이는데? 이거 확실해?","JPN":"待ってよ、文字がぼやけててよく見えないよ。本当にこれなの？","ENG":"Wait, the print is all smudged and hard to read. Are you sure this is it?","TWN":"等一下，字有點模糊，看不清楚，你確定嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"확실하거든~? 마시멜로 만들 때, 녹색병에 있는 가루를 넣는 걸 봤단 말이야.","JPN":"合ってるよ～マシュマロを作る時、緑のビンに入ってる粉を入れるのを見たんだから。","ENG":"Of course! I saw her using the powder from a green bottle when making those marshmallows.","TWN":"我很確定好嗎～？我看到她們在做棉花糖時，往裡面加了綠色瓶子的粉末。"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"자, 수녀님. 여기 젤라틴 파우더요.","JPN":"どうぞ、シスター。ゼラチンパウダーです。","ENG":"Here you go, Sister. This is the gelatin powder.","TWN":"來，修女，這是吉利丁粉。"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"두 분 모두 정말 감사해요.","JPN":"お二人とも、本当にありがとうございます。","ENG":"I cannot thank the two of you enough.","TWN":"真的非常感謝兩位。"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"에헤헤, 저희도 도움이 돼서 기뻐요. 그리고 저희 가게에서는 쓰는 초콜릿은 이쪽에…… ","JPN":"えへへ、私たちも役に立てて嬉しいです。それから、このお店で使ってるチョコレートはここに……","ENG":"Eh he he. We're also happy to help. And now, the chocolate that we use should be this way...","TWN":"嘿嘿，我們也很高興能幫上忙，而且我們店裡用的巧克力在這邊……"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_DOOR_SLIDE"},{"id":"L26_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"DORMITORY_3","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"왜 그래, 유나?","JPN":"どうした？　ユナ。","ENG":"What is it, Yuna?","TWN":"怎麼了，尤娜？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"어, 없어…! 초콜릿이 없어……!","JPN":"な、ない……！　チョコレートがない……！","ENG":"I-it's gone...! The chocolate...!","TWN":"啊，沒了……！巧克力沒了……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L32_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"무슨 헛소리야? 엊그제 새로 들어온 초콜릿이 벌써 떨어졌다고?","JPN":"何言ってるんだよ？　一昨日新しく買ってきたチョコレートをもう使い切ったの？","ENG":"What are you talking about? We couldn't have run out of chocolate when we just bought some a few days ago.","TWN":"說什麼呢？前幾天新進的巧克力已經吃完了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"앗!? 호, 혹시……!?","JPN":"あっ！？　も、もしかして……！？","ENG":"Huh?! I-is it because...","TWN":"啊？！難、難道……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"트리플 민트 초코… 어제 잔뜩 만들어서 냉장고에 넣어놨거든. 어쩌면 그게…….","JPN":"トリプルミントチョコ……昨日たくさん作って冷蔵庫に入れておいたの。もしかしてあれが……","ENG":"The Triple Mint Chocolate... I made a bunch yesterday and placed them in the fridge. I think that's why...","TWN":"三重薄荷巧克力……昨天做了很多，放在冰箱裡了。也許就是因為那個……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"뭐? 그럼 일주일 치 초콜릿을 전부 써버렸단 말이야? 그럼 다른 초콜릿 메뉴는 어떡해?","JPN":"はあ？　じゃあ、一週間分のチョコレートを全部使っちゃったわけ？　じゃあ、他のチョコレートメニューはどうするんだよ？","ENG":"What? So, you used up a week's supply of chocolate? Then, what about the other desserts that have chocolate in them?","TWN":"什麼？那就是說一周的巧克力全都用完了？那其他巧克力甜品怎麼辦？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"미안… 나는 가게에 여분이 남아 있을 줄 알았는데…….","JPN":"ごめん……私はお店に残りがあると思ってたんだけど……","ENG":"I'm sorry... I thought we had more...","TWN":"抱歉……我以為店裡還有多餘的……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"쳇, 어쩔 수 없지!","JPN":"ちっ、仕方ないね！","ENG":"Tch, there's no crying over spilled milk!","TWN":"嘖，沒辦法了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"이렇게 된 이상, 라우라가 돌아오기 전에 어디선가 초콜릿을 공수하는 수밖에 없어!","JPN":"こうなったら、ラウラが戻ってくる前にどこからかチョコレートを持ってくるしかないよ！","ENG":"The only thing we can do now is get more chocolate from somewhere before Laura gets back!","TWN":"既然如此，只能在蘿拉回來之前從某個地方弄到巧克力了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"그렇지만 어디에서……?","JPN":"でも、どこから……？","ENG":"But from where...?","TWN":"可是從哪裡……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저… 두 분 말씀 중에 죄송하지만…….","JPN":"あの……お二人とも、会話の途中で申し訳ないですけど……","ENG":"Um... I'm sorry to interrupt you two, but...","TWN":"那……打擾一下你們兩位……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"초콜릿이라면 저한테 한 가지 정보가 있는데요.","JPN":"チョコレートなら、私に情報があります。","ENG":"If you are looking for some chocolate, I think I know where to get some.","TWN":"如果是巧克力的話，我有一個情報。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"정보라고요?","JPN":"情報？","ENG":"You do?","TWN":"情報？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"네, <color=#ffd34c>특별한 초콜릿</color>을 만들 수 있는 분을 알고 있거든요.","JPN":"はい、<color=#ffd34c>特別なチョコレート</color>を作れる方を知っています。","ENG":"Yes. I know someone who can make <color=#ffd34c>special chocolate</color>.","TWN":"是的，我知道有人能做<color=#ffd34c>特別的巧克力</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};